fn edge_key(edge: &Edge) -> (String, String, String) {
    (
        edge.source_id.clone(),
        edge.target_id.clone(),
        edge.relation.as_str().to_string(),
    )
}

pub(super) fn node_exists_on(connection: &Connection, id: &str) -> Result<bool> {
    let count: i64 = connection.query_row(
        "SELECT COUNT(1) FROM nodes WHERE id = ?1",
        params![id],
        |row| row.get(0),
    )?;
    Ok(count > 0)
}

pub(super) fn upsert_node_on(connection: &Connection, node: &Node) -> Result<bool> {
    let existed = node_exists_on(connection, &node.id)?;
    connection.execute(
        "INSERT INTO nodes (id, type, label, content, created_at, last_accessed_at)
         VALUES (?1, ?2, ?3, ?4, ?5, ?6)
         ON CONFLICT(id) DO UPDATE SET
             label = excluded.label,
             content = COALESCE(excluded.content, nodes.content),
             last_accessed_at = excluded.last_accessed_at",
        params![
            node.id,
            node.node_type.as_str(),
            node.label,
            node.content,
            node.created_at,
            node.last_accessed_at,
        ],
    )?;
    Ok(!existed)
}

pub(super) fn upsert_edge_on(
    connection: &Connection,
    edge: &Edge,
    owner_id: Option<&str>,
) -> Result<bool> {
    let existing_owner: Option<Option<String>> = connection
        .query_row(
            "SELECT owner_id FROM edges
             WHERE source_id = ?1 AND target_id = ?2 AND relation = ?3",
            params![edge.source_id, edge.target_id, edge.relation.as_str()],
            |row| row.get(0),
        )
        .optional()?;
    if let (Some(requested), Some(Some(existing))) = (owner_id, existing_owner.as_ref()) {
        if requested != existing {
            return Err(MindLeakError::Other(format!(
                "structural edge is owned by {existing}, not {requested}"
            )));
        }
    }
    let existed = existing_owner.is_some();
    connection.execute(
        "INSERT INTO edges (
             source_id, target_id, relation, weight, half_life_hours, updated_at,
             first_seen, reinforcement_count, owner_id
         )
         VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?6, 1, ?7)
         ON CONFLICT(source_id, target_id, relation) DO UPDATE SET
             weight = MIN(1.0, edges.weight + 0.05),
             half_life_hours = excluded.half_life_hours,
             updated_at = excluded.updated_at,
             reinforcement_count = edges.reinforcement_count + 1,
             owner_id = COALESCE(excluded.owner_id, edges.owner_id)",
        params![
            edge.source_id,
            edge.target_id,
            edge.relation.as_str(),
            edge.weight,
            edge.half_life_hours,
            edge.updated_at,
            owner_id,
        ],
    )?;
    Ok(!existed)
}

fn structural_source_belongs_to_owner(edge: &Edge, owner_id: &str) -> bool {
    if edge.source_id == owner_id {
        return true;
    }
    let artifact_path = owner_id.strip_prefix("artifact:").unwrap_or(owner_id);
    edge.source_id
        .starts_with(&format!("symbol:{artifact_path}:"))
}

pub(super) fn delete_orphan_artifact_stubs(connection: &Connection) -> Result<usize> {
    Ok(connection.execute(
        "DELETE FROM nodes
         WHERE id IN (SELECT node_id FROM artifact_stubs)
           AND NOT EXISTS (
               SELECT 1 FROM edges
               WHERE source_id = nodes.id OR target_id = nodes.id
           )",
        [],
    )?)
}

fn promote_artifact_stub(connection: &Connection, stub_id: &str, real_id: &str) -> Result<()> {
    connection.execute(
        "INSERT OR IGNORE INTO edges (
             source_id, target_id, relation, weight, half_life_hours, updated_at,
             first_seen, reinforcement_count, owner_id
         )
         SELECT source_id, ?2, relation, weight, half_life_hours, updated_at,
                first_seen, reinforcement_count, owner_id
         FROM edges
         WHERE target_id = ?1 AND relation = 'imports'",
        params![stub_id, real_id],
    )?;
    connection.execute(
        "DELETE FROM edges WHERE target_id = ?1 AND relation = 'imports'",
        params![stub_id],
    )?;

    let stub_path = stub_id.strip_prefix("artifact:").unwrap_or(stub_id);
    let real_path = real_id.strip_prefix("artifact:").unwrap_or(real_id);
    let stub_symbol_prefix = format!("symbol:{stub_path}:");
    let structural_targets = {
        let mut statement = connection.prepare(
            "SELECT DISTINCT target_id
             FROM edges
             WHERE relation IN ('calls', 'extends', 'implements')
               AND substr(target_id, 1, length(?1)) = ?1",
        )?;
        let rows =
            statement.query_map(params![stub_symbol_prefix], |row| row.get::<_, String>(0))?;
        let mut targets = Vec::new();
        for row in rows {
            targets.push(row?);
        }
        targets
    };
    for old_target in structural_targets {
        let symbol_name = &old_target[stub_symbol_prefix.len()..];
        let new_target = format!("symbol:{real_path}:{symbol_name}");
        if node_exists_on(connection, &new_target)? {
            connection.execute(
                "INSERT OR IGNORE INTO edges (
                     source_id, target_id, relation, weight, half_life_hours, updated_at,
                     first_seen, reinforcement_count, owner_id
                 )
                 SELECT source_id, ?2, relation, weight, half_life_hours, updated_at,
                        first_seen, reinforcement_count, owner_id
                 FROM edges
                                 WHERE target_id = ?1
                                     AND relation IN ('calls', 'extends', 'implements')",
                params![old_target, new_target],
            )?;
        }
        connection.execute(
            "DELETE FROM edges
                         WHERE target_id = ?1
                             AND relation IN ('calls', 'extends', 'implements')",
            params![old_target],
        )?;
        connection.execute(
            "DELETE FROM nodes
             WHERE id = ?1 AND type = 'symbol'
               AND NOT EXISTS (
                   SELECT 1 FROM edges WHERE source_id = ?1 OR target_id = ?1
               )",
            params![old_target],
        )?;
    }
    connection.execute(
        "DELETE FROM nodes
         WHERE id = ?1
           AND NOT EXISTS (
               SELECT 1 FROM edges WHERE source_id = ?1 OR target_id = ?1
           )",
        params![stub_id],
    )?;
    Ok(())
}

